<tr><td><time datetime="<?=atenea_e((string)$r['created_at'])?>"><?=atenea_e(date('d/m/Y h:i A',strtotime((string)$r['created_at'])))?></time><?php if($r['restaurado_at']):?><small class="d-block text-muted">Restaurada <?=atenea_e(date('d/m/Y h:i A',strtotime((string)$r['restaurado_at'])))?></small><?php endif;?></td><td><?=atenea_e(trim((string)($r['creador']?:'Proceso del sistema')))?></td><td><?=($r['tipo']==='previo_restauracion')?'Previa a restauración':'Manual'?></td><td><?=atenea_e(formatoTamanoRespaldo($r['tamano_bytes']===null?null:(int)$r['tamano_bytes']))?></td><td><span class="text-nowrap"><?=(int)$r['tablas_incluidas']?> tablas</span><small class="d-block text-muted"><?=number_format((int)$r['filas_incluidas'],0,',','.')?> filas</small></td><td><span class="badge bg-<?=$estado[1]?>"><?=atenea_e($estado[0])?></span><?php if($r['error_sanitizado']):?><small class="d-block text-danger mt-1"><?=atenea_e((string)$r['error_sanitizado'])?></small><?php endif;?></td><td><div class="d-flex gap-1 justify-content-end flex-wrap">
<?php if($disponible):?><form method="post" action="descargar.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-primary" title="Descargar copia"><i class="mdi mdi-download"></i><span class="visually-hidden">Descargar</span></button></form><?php endif;?>
