<?php if($superadmin):?><div class="modal fade" id="modalRestaurar" tabindex="-1" aria-labelledby="tituloRestaurar" aria-hidden="true"><div class="modal-dialog modal-dialog-centered"><div class="modal-content"><form method="post" action="accion.php" id="formRestaurar" data-atenea-loading data-atenea-loading-title="Restaurando base de datos"><div class="modal-header"><h2 class="modal-title h5" id="tituloRestaurar">Restaurar copia de seguridad</h2><button type="button" class="btn-close" data-bs-dismiss="modal" aria-label="Cerrar"></button></div><div class="modal-body"><div class="alert alert-danger"><strong>Acción crítica.</strong> La base actual será reemplazada. Atenea creará automáticamente una copia previa antes de comenzar.</div><p>Copia seleccionada: <strong data-backup-date></strong></p><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="accion" value="restaurar"><input type="hidden" name="id" value=""><div class="mb-3"><label class="form-label" for="backup-password">Contraseña actual</label><input class="form-control" id="backup-password" type="password" name="password" autocomplete="current-password" required></div><div class="mb-3"><label class="form-label" for="backup-phrase">Escribe <strong data-backup-phrase></strong></label><input class="form-control" id="backup-phrase" name="frase" autocomplete="off" required></div><div class="form-check"><input class="form-check-input" type="checkbox" value="1" name="confirmar_riesgo" id="confirmar-riesgo" required><label class="form-check-label" for="confirmar-riesgo">Comprendo que la información actual será reemplazada.</label></div></div><div class="modal-footer"><button type="button" class="btn btn-light" data-bs-dismiss="modal">Cancelar</button><button class="btn btn-danger">Continuar con la restauración</button></div></form></div></div></div>
<script>document.addEventListener('DOMContentLoaded',()=>{const modalEl=document.getElementById('modalRestaurar'),form=document.getElementById('formRestaurar'),modal=modalEl&&window.bootstrap?new bootstrap.Modal(modalEl):null;document.querySelectorAll('.js-restaurar').forEach(button=>button.addEventListener('click',()=>{const id=button.dataset.id,phrase='RESTAURAR '+id;form.elements.id.value=id;form.elements.password.value='';form.elements.frase.value='';form.elements.confirmar_riesgo.checked=false;modalEl.querySelector('[data-backup-date]').textContent=button.dataset.fecha;modalEl.querySelector('[data-backup-phrase]').textContent=phrase;modal?.show();}));form?.addEventListener('submit',async event=>{if(form.dataset.confirmed==='1')return;event.preventDefault();const ok=window.AteneaAlerts?await AteneaAlerts.confirm({title:'Segunda confirmación',message:'Se creará una copia previa y luego se reemplazará la base de datos actual. No cierres esta ventana.',danger:true,confirmText:'Sí, restaurar ahora'}):confirm('¿Confirmas por segunda vez la restauración?');if(ok){form.dataset.confirmed='1';form.requestSubmit();}});});</script><?php endif;?>
